(() => {
  class ChartLite {
    constructor(target, config = {}) {
      this.canvas = target && target.getContext ? target : document.getElementById(target);
      this.ctx = this.canvas ? this.canvas.getContext("2d") : null;
      this.config = config;
      if (!this.ctx || !this.canvas) return;
      this.render();
    }

    static get defaults() {
      return {
        color: "#9fb2c6",
        borderColor: "rgba(159, 178, 198, 0.32)",
        font: "12px sans-serif",
      };
    }

    _setupCanvas() {
      const ratio = window.devicePixelRatio || 1;
      const width = this.canvas.clientWidth || 520;
      const height = this.canvas.clientHeight || Number(this.canvas.getAttribute("height")) || 160;
      this.canvas.width = Math.floor(width * ratio);
      this.canvas.height = Math.floor(height * ratio);
      this.ctx.setTransform(ratio, 0, 0, ratio, 0, 0);
      this.ctx.clearRect(0, 0, width, height);
      return { width, height };
    }

    _options() {
      return this.config.options || {};
    }

    _dataset(index = 0) {
      const ds = (this.config.data && this.config.data.datasets && this.config.data.datasets[index]) || {};
      return ds;
    }

    _labels() {
      return (this.config.data && this.config.data.labels) || [];
    }

    _values(index = 0) {
      const ds = this._dataset(index);
      return Array.isArray(ds.data) ? ds.data.map((value) => Number(value) || 0) : [];
    }

    _text(color) {
      this.ctx.fillStyle = color || ChartLite.defaults.color;
      this.ctx.font = ChartLite.defaults.font;
    }

    _drawGrid({ left, top, right, bottom, steps = 4 }) {
      this.ctx.strokeStyle = "rgba(159,178,198,0.18)";
      this.ctx.lineWidth = 1;
      for (let i = 0; i <= steps; i += 1) {
        const y = top + ((bottom - top) / steps) * i;
        this.ctx.beginPath();
        this.ctx.moveTo(left, y);
        this.ctx.lineTo(right, y);
        this.ctx.stroke();
      }
    }

    _drawLine() {
      const { width, height } = this._setupCanvas();
      const labels = this._labels();
      const values = this._values(0);
      const ds = this._dataset(0);
      const left = 30;
      const right = width - 12;
      const top = 12;
      const bottom = height - 24;
      const span = Math.max(...values, 1);
      const xStep = values.length > 1 ? (right - left) / (values.length - 1) : 0;

      this._drawGrid({ left, top, right, bottom });
      this.ctx.strokeStyle = ds.borderColor || "#f0d4a5";
      this.ctx.lineWidth = 2;
      this.ctx.beginPath();
      values.forEach((value, idx) => {
        const x = left + idx * xStep;
        const y = bottom - ((value || 0) / span) * (bottom - top);
        if (idx === 0) this.ctx.moveTo(x, y);
        else this.ctx.lineTo(x, y);
      });
      this.ctx.stroke();

      this.ctx.fillStyle = ds.backgroundColor || "rgba(240,212,165,0.16)";
      this.ctx.beginPath();
      values.forEach((value, idx) => {
        const x = left + idx * xStep;
        const y = bottom - ((value || 0) / span) * (bottom - top);
        if (idx === 0) this.ctx.moveTo(x, y);
        else this.ctx.lineTo(x, y);
      });
      this.ctx.lineTo(right, bottom);
      this.ctx.lineTo(left, bottom);
      this.ctx.closePath();
      this.ctx.fill();

      this._text();
      labels.forEach((label, idx) => {
        if (idx % Math.ceil(labels.length / 6 || 1) !== 0 && idx !== labels.length - 1) return;
        const x = left + idx * xStep;
        this.ctx.fillText(String(label), x - 12, height - 6);
      });
    }

    _drawBar() {
      const { width, height } = this._setupCanvas();
      const labels = this._labels();
      const values = this._values(0);
      const ds = this._dataset(0);
      const left = 24;
      const right = width - 10;
      const top = 12;
      const bottom = height - 20;
      const span = Math.max(...values, 1);
      const slot = values.length ? (right - left) / values.length : 0;
      const barWidth = Math.max(8, slot * 0.62);

      this._drawGrid({ left, top, right, bottom });
      this.ctx.fillStyle = ds.backgroundColor || "rgba(116,164,231,0.68)";
      values.forEach((value, idx) => {
        const x = left + idx * slot + (slot - barWidth) / 2;
        const barHeight = ((value || 0) / span) * (bottom - top);
        const y = bottom - barHeight;
        this.ctx.fillRect(x, y, barWidth, barHeight);
      });

      this._text();
      labels.forEach((label, idx) => {
        if (idx % Math.ceil(labels.length / 7 || 1) !== 0 && idx !== labels.length - 1) return;
        const x = left + idx * slot;
        this.ctx.fillText(String(label), x, height - 6);
      });
    }

    _drawDoughnut() {
      const { width, height } = this._setupCanvas();
      const values = this._values(0);
      const labels = this._labels();
      const ds = this._dataset(0);
      const colors = Array.isArray(ds.backgroundColor) && ds.backgroundColor.length
        ? ds.backgroundColor
        : ["#f0d4a5", "#74a4e7", "#e1ac5c", "#3fbe8a", "#e77474", "#9eafc3"];
      const total = Math.max(values.reduce((acc, item) => acc + item, 0), 1);
      const cx = width / 2;
      const cy = height / 2 - 4;
      const radius = Math.min(width, height) * 0.32;
      const inner = radius * 0.62;

      let start = -Math.PI / 2;
      values.forEach((value, idx) => {
        const angle = (value / total) * Math.PI * 2;
        this.ctx.beginPath();
        this.ctx.moveTo(cx, cy);
        this.ctx.fillStyle = colors[idx % colors.length];
        this.ctx.arc(cx, cy, radius, start, start + angle);
        this.ctx.closePath();
        this.ctx.fill();
        start += angle;
      });

      this.ctx.globalCompositeOperation = "destination-out";
      this.ctx.beginPath();
      this.ctx.arc(cx, cy, inner, 0, Math.PI * 2);
      this.ctx.fill();
      this.ctx.globalCompositeOperation = "source-over";

      this._text();
      this.ctx.textAlign = "center";
      this.ctx.fillStyle = "#e7edf5";
      this.ctx.fillText("Estados", cx, cy + 4);
      this.ctx.textAlign = "left";

      const legendX = 10;
      let legendY = height - Math.min(labels.length * 15, 62);
      labels.slice(0, 4).forEach((label, idx) => {
        this.ctx.fillStyle = colors[idx % colors.length];
        this.ctx.fillRect(legendX, legendY - 7, 10, 10);
        this.ctx.fillStyle = "#9fb2c6";
        this.ctx.fillText(`${label}: ${values[idx] || 0}`, legendX + 14, legendY + 1);
        legendY += 15;
      });
    }

    render() {
      if (!this.ctx || !this.canvas) return;
      const type = (this.config.type || "line").toLowerCase();
      if (type === "bar") {
        this._drawBar();
      } else if (type === "doughnut") {
        this._drawDoughnut();
      } else {
        this._drawLine();
      }
    }

    destroy() {
      if (!this.ctx || !this.canvas) return;
      const width = this.canvas.clientWidth || 0;
      const height = this.canvas.clientHeight || 0;
      this.ctx.clearRect(0, 0, width, height);
    }
  }

  window.Chart = ChartLite;
})();
